import mongoose from 'mongoose';
import UserSetting from ".model/UserSetting.js";

async function createDefaultUserSetting(userId) {
    try {
        const existing = await UserSetting.findOne({ userId });

        if (existing) {
            console.log('UserSetting already exists for', userId);
            return existing;
        }

        const defaultSettings = {
            userId,
            dailyStudyMinutes: 120,
            studyDaysPerWeek: 5,
            breakDuration: 30,
            maxWeeklyWorkload: 600
        }
        const userSetting = await UserSetting.create(defaultSettings);
        console.log('Default UserSetting created for', userId);
        return userSetting;

    }
    catch (err) {
        console.log('Please refresh and make sure userId is correct');
        console.error('Error creating default user setting for', userId, ':', err);
    }


}
